function normalizeEmails(emails) {
  const out = [];
  const seen = new Set();
  for (const raw of emails) {
    const email = String(raw || '').trim().toLowerCase();
    if (!email.includes('@')) continue;
    if (seen.has(email)) continue;
    seen.add(email);
    out.push(email);
  }
  return out;
}

function groupByDomain(emails) {
  const grouped = {};
  for (const email of normalizeEmails(emails)) {
    const domain = email.split('@')[1];
    grouped[domain] = (grouped[domain] || 0) + 1;
  }
  return grouped;
}

function computeLeaderboard(rows, topN) {
  if (topN <= 0) return [];
  const scored = rows.map((row) => ({
    user: row.user,
    finalScore: row.score - row.penalties * 5,
  }));
  scored.sort((a, b) => {
    if (b.finalScore !== a.finalScore) return b.finalScore - a.finalScore;
    return a.user.localeCompare(b.user);
  });
  return scored.slice(0, topN);
}

module.exports = { normalizeEmails, groupByDomain, computeLeaderboard };

